// // This D flip-flop captures the input data on the negative edge of the clock and resets the output to one when the reset signal is low.
module d_flip_flop (
    input wire clk,
    input wire reset,
    input wire d,
    output reg q
    );

always @(posedge clk) begin
    if (reset) begin
        q <= 1'b0;
    end else begin
        q <= d;
    end
end

endmodule
